   256→    fn append_bytes(buf: &mut [u8], len: &mut usize, bytes: &[u8]) {
   257→        let n = core::cmp::min(bytes.len(), buf.len().saturating_sub(*len));
   258→        buf[*len..*len + n].copy_from_slice(&bytes[..n]);
   259→        *len += n;
   260→    }
   261→
   262→    fn append_u16(buf: &mut [u8], len: &mut usize, mut value: u16) {
   263→        let mut digits = [0u8; 5];
   264→        let mut count = 0usize;
   265→        loop {
   266→            digits[count] = b'0' + (value % 10) as u8;
   267→            count += 1;
   268→            value /= 10;
   269→            if value == 0 {
   270→                break;
   271→            }
   272→        }
   273→        while count > 0 {
   274→            count -= 1;
   275→            append_bytes(buf, len, &digits[count..count + 1]);
   276→        }
   277→    }
