   426→    #[panic_handler]
   427→    fn panic(info: &core::panic::PanicInfo<'_>) -> ! {
   428→        // Emit a deterministic crash report via USB Serial/JTAG so the panic
   429→        // location is visible on the host instead of the device freezing silently.
   430→        serial_write_bytes(b"\r\n!!! PANIC !!!\r\n");
   431→        if let Some(loc) = info.location() {
   432→            // Format "file:line\r\n" into a small stack buffer; no heap needed.
   433→            let mut buf = [0u8; 128];
   434→            let mut cursor = &mut buf[..];
   435→            let _ = write!(cursor, "{}:{}\r\n", loc.file(), loc.line());
   436→            let written = 128 - cursor.len();
   437→            serial_write_bytes(&buf[..written]);
   438→        }
   439→        loop {
   440→            spin_loop();
   441→        }
   442→    }
