   444→    // ── F9: Launcher + app-load Embassy task ──────────────────────────────────
   445→    #[embassy_executor::task]
   446→    async fn launcher_task(_spawner: Spawner) {
   447→        unsafe {
   448→            if TRANSPORT_PTR.is_null() || LAUNCHER_BUF_PTR.is_null() {
   449→                loop {
   450→                    spin_loop();
   451→                }
   452→            }
   453→
   454→            let launcher_buf = &mut *LAUNCHER_BUF_PTR;
   455→
   456→            if BUTTON_DIAGNOSTIC_MODE {
   457→                let mut last_event = None;
   458→                let mut last_snapshot = ButtonDiagSnapshot {
   459→                    gpio1_mv: u16::MAX,
   460→                    gpio2_mv: u16::MAX,
   461→                    gpio1_decoded: None,
   462→                    gpio2_decoded: None,
   463→                    stable: None,
   464→                    last_event: None,
   465→                };
   466→
   467→                loop {
   468→                    if INPUT_PTR.is_null() {
   469→                        render_boot_placeholder(launcher_buf, BootFailureKind::None);
   470→                        device_refresh_frame(launcher_buf);
   471→                        loop {
   472→                            spin_loop();
   473→                        }
   474→                    }
   475→
   476→                    if let Ok(event) = (&mut *INPUT_PTR).poll() {
   477→                        if let Some(event) = event {
   478→                            last_event = Some(event);
   479→                        }
   480→                    }
   481→
   482→                    let (gpio1_mv, gpio2_mv) = (&*INPUT_PTR).last_samples();
   483→                    let (gpio1_decoded, gpio2_decoded) = (&*INPUT_PTR).last_decoded();
   484→                    let snapshot = ButtonDiagSnapshot {
   485→                        gpio1_mv,
   486→                        gpio2_mv,
   487→                        gpio1_decoded,
   488→                        gpio2_decoded,
   489→                        stable: (&*INPUT_PTR).current_button(),
   490→                        last_event,
   491→                    };
   492→
   493→                    if snapshot != last_snapshot {
   494→                        render_button_diagnostics(launcher_buf, &snapshot);
   495→                        device_refresh_frame(launcher_buf);
   496→                        last_snapshot = snapshot;
   497→                    }
   498→
   499→                    Delay::new().delay_millis(20);
   500→                }
   501→            }
   502→
   503→            if FS_PTR.is_null() || APP_REGION_PTR.is_null() || PDB_BUF_PTR.is_null() {
   504→                render_boot_placeholder(launcher_buf, BOOT_FAILURE);
   505→                device_refresh_frame(launcher_buf);
   506→                loop {
   507→                    spin_loop();
   508→                }
   509→            }
   510→
   511→            let fs = &mut *FS_PTR;
   512→            let app_region = &mut (&mut *APP_REGION_PTR)[..];
   513→            let pdb_buf = &mut (&mut *PDB_BUF_PTR)[..];
   514→
   515→            loop {
   516→                let filename = run_launcher_with_refresh(fs, launcher_buf, device_refresh_frame);
   517→                serial_write_bytes(b"LAUNCH:confirm\n");
   518→                let syscalls = build_syscall_table(app_region.as_ptr() as u32, app_region.len() as u32);
   519→                let mode = if LAUNCH_DRY_RUN {
   520→                    JumpMode::DryRun
   521→                } else {
   522→                    JumpMode::Jump(jump_to_app)
   523→                };
   524→                let _ = load_and_run(fs, &filename, pdb_buf, app_region, &syscalls, mode);
   525→            }
   526→        }
   527→    }
