   529→    #[main]
   530→    fn main() -> ! {
   531→        let config = Config::default().with_cpu_clock(CpuClock::max());
   532→        let peripherals = esp_hal::init(config);
   533→
   534→        // ── G1: USB Serial/JTAG console — must come first so panics can emit ──
   535→        let serial = SERIAL_CELL.init(UsbSerialJtag::new(peripherals.USB_DEVICE));
   536→        // SAFETY: written once before any task or panic handler runs; single-core.
   537→        unsafe {
   538→            SERIAL_PTR = serial as *mut _;
   539→            set_serial_write_fn(device_serial_write);
   540→        }
   541→        serial_write_bytes(b"\r\nPaperDOS kernel boot\r\n");
   542→
   543→        let adc1 = unsafe { peripherals.ADC1.clone_unchecked() };
   544→        let gpio1 = unsafe { peripherals.GPIO1.clone_unchecked() };
   545→        let gpio2 = unsafe { peripherals.GPIO2.clone_unchecked() };
   546→
   547→        let tx_buf = DmaTxBuf::new(
   548→            TX_DESC.init([DmaDescriptor::EMPTY; 2]),
   549→            TX_BUF.init([0u8; 4096]),
   550→        )
   551→        .unwrap();
   552→        let rx_buf = DmaRxBuf::new(
   553→            RX_DESC.init([DmaDescriptor::EMPTY; 2]),
   554→            RX_BUF.init([0u8; 4096]),
   555→        )
   556→        .unwrap();
   557→
   558→        let mut spi_raw = spi::master::Spi::new(
   559→            peripherals.SPI2,
   560→            SpiConfig::default()
   561→                .with_frequency(Rate::from_khz(400))
   562→                .with_mode(Mode::_0),
   563→        )
   564→        .unwrap()
   565→        .with_sck(peripherals.GPIO8)
   566→        .with_mosi(peripherals.GPIO10)
   567→        .with_miso(peripherals.GPIO7);
   568→        let _ = spi_raw.write(&[0xFF; 10]);
   569→        let spi_bus = spi_raw
   570→            .with_dma(peripherals.DMA_CH0)
   571→            .with_buffers(rx_buf, tx_buf);
   572→        let spi_ref = SPI_BUS_CELL.init(Mutex::new(RefCell::new(spi_bus)));
   573→
   574→        let fs = if BUTTON_DIAGNOSTIC_MODE {
   575→            Err(BootFailureKind::None)
   576→        } else {
   577→            let sd_spi: SdSpiDevice<'static, Delay> = CriticalSectionDevice::new(
   578→                spi_ref,
   579→                DummyCsPin,
   580→                Delay::new(),
   581→            )
   582→            .unwrap();
   583→            DeviceFs::from_spi2(
   584→                sd_spi,
   585→                // SAFETY: GPIO12 is free for SD CS on the X4 in DIO flash mode.
   586→                unsafe { RawOutputPin::new(12) },
   587→                Delay::new(),
   588→            )
   589→            .map_err(|err| map_boot_failure("sd_init", err))
   590→        };
   591→
   592→        let display_spi = CriticalSectionDevice::new(
   593→            spi_ref,
   594→            Output::new(peripherals.GPIO21, Level::High, OutputConfig::default()),
   595→            Delay::new(),
   596→        )
   597→        .unwrap();
   598→        let mut display = X4DisplayTransport::new(
   599→            display_spi,
   600→            peripherals.GPIO4,
   601→            peripherals.GPIO5,
   602→            peripherals.GPIO6,
   603→        );
   604→        emit_reset_preamble(&mut display).unwrap();
   605→        emit_power_init_block(&mut display).unwrap();
   606→        emit_addressing_init_block(&mut display).unwrap();
   607→
   608→        // F8: Store the transport and wire all device globals before spawning tasks.
   609→        let transport_ref = TRANSPORT_CELL.init(display);
   610→        let launcher_buf_ref = LAUNCHER_BUF_CELL.init([0xFF; FRAME_BYTES]);
   611→        let app_region_ref = APP_REGION_CELL.init([0u8; APP_REGION_BYTES]);
   612→        let pdb_buf_ref = PDB_BUF_CELL.init([0u8; PDB_BUF_BYTES]);
   613→        let fs_ref = match fs {
   614→            Ok(fs) => FS_CELL.init(fs) as *mut _,
   615→            Err(failure) => {
