   621→        unsafe {
   622→            TRANSPORT_PTR = transport_ref as *mut _;
   623→            FS_PTR = fs_ref;
   624→            LAUNCHER_BUF_PTR = launcher_buf_ref as *mut _;
   625→            APP_REGION_PTR = app_region_ref as *mut _;
