    71→/// Test double: replays scripted SPI transaction replies and records sent bytes.
    72→///
    73→/// Each entry in `replies` is a byte sequence returned for one `transaction()` call.
    74→/// When transactions exceed pre-loaded replies, subsequent reads return 0xFF.
    75→pub struct MockSpi {
    76→    replies: Vec<Vec<u8>>,
    77→    reply_idx: usize,
    78→    /// All bytes written via Write and Transfer operations, in order.
    79→    pub sent: Vec<u8>,
    80→}
    81→
    82→impl MockSpi {
    83→    /// `replies[i]` is the byte sequence returned during the i-th `transaction()` call.
    84→    pub fn new(replies: &[&[u8]]) -> Self {
    85→        Self {
    86→            replies: replies.iter().map(|s| s.to_vec()).collect(),
    87→            reply_idx: 0,
    88→            sent: Vec::new(),
    89→        }
    90→    }
    91→}
    92→
    93→impl SpiDevice for MockSpi {
    94→    fn transaction(&mut self, operations: &mut [Operation<'_, u8>]) -> Result<(), Self::Error> {
    95→        let reply = if self.reply_idx < self.replies.len() {
    96→            let r = self.replies[self.reply_idx].clone();
    97→            self.reply_idx += 1;
    98→            r
    99→        } else {
   100→            Vec::new()
   101→        };
   102→        let mut reply_pos = 0usize;
   103→
   104→        for op in operations.iter_mut() {
   105→            match op {
   106→                Operation::Write(bytes) => {
   107→                    self.sent.extend_from_slice(bytes);
   108→                }
   109→                Operation::Read(buf) => {
   110→                    for b in buf.iter_mut() {
   111→                        *b = if reply_pos < reply.len() {
   112→                            let v = reply[reply_pos];
   113→                            reply_pos += 1;
   114→                            v
   115→                        } else {
   116→                            0xFF
   117→                        };
   118→                    }
   119→                }
   120→                Operation::Transfer(read, write) => {
   121→                    self.sent.extend_from_slice(write);
   122→                    for b in read.iter_mut() {
   123→                        *b = if reply_pos < reply.len() {
   124→                            let v = reply[reply_pos];
   125→                            reply_pos += 1;
   126→                            v
   127→                        } else {
   128→                            0xFF
   129→                        };
   130→                    }
   131→                }
   132→                Operation::TransferInPlace(buf) => {
   133→                    let written: Vec<u8> = buf.to_vec();
   134→                    self.sent.extend_from_slice(&written);
   135→                    for b in buf.iter_mut() {
   136→                        *b = if reply_pos < reply.len() {
   137→                            let v = reply[reply_pos];
   138→                            reply_pos += 1;
   139→                            v
   140→                        } else {
   141→                            0xFF
   142→                        };
   143→                    }
   144→                }
   145→                Operation::DelayNs(_) => {}
   146→            }
   147→        }
   148→        Ok(())
   149→    }
   150→}
