   156→/// In-memory block device for filesystem integration tests.
   157→///
   158→/// Holds a pre-populated `Vec<Block>` in a `RefCell`. Reads beyond the
   159→/// pre-populated range return zero blocks; out-of-range writes are silently
   160→/// dropped. `num_blocks()` returns the length of the inner Vec.
   161→pub struct InMemoryBlockDevice {
   162→    blocks: RefCell<Vec<Block>>,
   163→}
   164→
   165→impl InMemoryBlockDevice {
   166→    /// Create a device backed by `blocks`. `num_blocks()` returns `blocks.len()`.
   167→    pub fn new(blocks: Vec<Block>) -> Self {
   168→        Self {
   169→            blocks: RefCell::new(blocks),
   170→        }
   171→    }
   172→}
   173→
   174→impl BlockDevice for InMemoryBlockDevice {
   175→    type Error = ();
   176→
   177→    fn read(
   178→        &self,
   179→        blocks: &mut [Block],
   180→        start_block_idx: BlockIdx,
   181→        _reason: &str,
   182→    ) -> Result<(), ()> {
   183→        let store = self.blocks.borrow();
   184→        for (i, block) in blocks.iter_mut().enumerate() {
   185→            let idx = start_block_idx.0 as usize + i;
   186→            if idx < store.len() {
   187→                block.contents.copy_from_slice(&store[idx].contents);
   188→            } else {
   189→                block.contents = [0u8; 512];
   190→            }
   191→        }
   192→        Ok(())
   193→    }
   194→
   195→    fn write(&self, blocks: &[Block], start_block_idx: BlockIdx) -> Result<(), ()> {
   196→        let mut store = self.blocks.borrow_mut();
   197→        for (i, block) in blocks.iter().enumerate() {
   198→            let idx = start_block_idx.0 as usize + i;
   199→            if idx < store.len() {
   200→                store[idx].contents.copy_from_slice(&block.contents);
   201→            }
   202→        }
   203→        Ok(())
   204→    }
   205→
   206→    fn num_blocks(&self) -> Result<BlockCount, ()> {
   207→        Ok(BlockCount(self.blocks.borrow().len() as u32))
   208→    }
   209→}
