   215→// ── PDB test helpers ──────────────────────────────────────────────────────────
   216→
   217→/// CRC32 (PKZIP polynomial) — mirrors the private implementation in `pdb.rs`.
   218→pub fn crc32_for_test(bytes: &[u8]) -> u32 {
   219→    let mut crc = 0xFFFF_FFFFu32;
   220→    for &byte in bytes {
   221→        crc ^= byte as u32;
   222→        for _ in 0..8 {
   223→            let mask = (crc & 1).wrapping_neg() & 0xEDB8_8320;
   224→            crc = (crc >> 1) ^ mask;
   225→        }
   226→    }
   227→    !crc
   228→}
