   230→/// Build a minimal valid PDB binary with the given `image` as the `.text` section.
   231→///
   232→/// Header fields: magic=PDOS, format_version=1, abi_version=1, entry_offset=0,
   233→/// text_size=len(image), data_size/bss_size/min_heap=0, reloc_count=0.
   234→/// Checksum is computed over the payload (image bytes only).
   235→pub fn make_min_pdb(image: &[u8]) -> Vec<u8> {
   236→    let payload = image.to_vec();
   237→    let checksum = crc32_for_test(&payload);
   238→
   239→    let mut bytes = vec![0u8; 104];
   240→    bytes[0x00..0x04].copy_from_slice(&0x534F4450u32.to_le_bytes()); // magic "PDOS"
   241→    bytes[0x04..0x06].copy_from_slice(&1u16.to_le_bytes()); // format_version
   242→    bytes[0x06..0x08].copy_from_slice(&1u16.to_le_bytes()); // abi_version
   243→    bytes[0x0C..0x10].copy_from_slice(&(image.len() as u32).to_le_bytes()); // text_size
   244→    bytes[0x20..0x24].copy_from_slice(b"test"); // app_name
   245→    bytes[0x40..0x44].copy_from_slice(b"1.0\0"); // app_version
   246→    bytes[0x64..0x68].copy_from_slice(&checksum.to_le_bytes()); // checksum
   247→    bytes.extend_from_slice(&payload);
   248→    bytes
   249→}
