   251→/// Build a minimal FAT16 disk image for filesystem tests.
   252→///
   253→/// Layout (device LBAs):
   254→/// - 0: MBR  — partition 1: type 0x06, LBA start=1, size=4200 sectors
   255→/// - 1: Boot sector — BPB: 512 B/sec, 1 sec/cluster, 1 reserved, 1 FAT,
   256→///       16 root entries, 4200 total sectors, FAT size=17 → cluster_count=4181
   257→/// - 2-18: FAT (17 sectors); sector 0 has entries 0-3 set, rest are zero (free)
   258→/// - 19: Root directory — README.TXT (cluster 2, size 6) + TESTDIR (cluster 3)
   259→/// - 20: Cluster 2 = "Hello!" content
   260→/// - 21: Cluster 3 = TESTDIR (empty, zeros)
   261→/// - 22-4200: zeros
   262→///
   263→/// `num_blocks()` = 4201.
   264→pub fn make_test_fat16_image() -> Vec<Block> {
   265→    const TOTAL: usize = 4201; // 1 MBR + 4200 partition sectors
   266→    let mut blocks = vec![Block::new(); TOTAL];
   267→
   268→    // ── Block 0: MBR ──────────────────────────────────────────────────────────
   269→    {
   270→        let b = &mut blocks[0].contents;
   271→        // Partition 1 entry at offset 446 (16 bytes)
   272→        b[446] = 0x00; // status: not bootable
   273→        b[447] = 0x00;
   274→        b[448] = 0x01;
   275→        b[449] = 0x00; // CHS start (ignored)
   276→        b[450] = 0x06; // type: FAT16
   277→        b[451] = 0x00;
   278→        b[452] = 0x00;
   279→        b[453] = 0x00; // CHS end (ignored)
   280→        b[454] = 0x01;
   281→        b[455] = 0x00;
   282→        b[456] = 0x00;
   283→        b[457] = 0x00; // LBA start = 1
   284→        b[458] = 0x68;
   285→        b[459] = 0x10;
   286→        b[460] = 0x00;
   287→        b[461] = 0x00; // num sectors = 4200
   288→        b[510] = 0x55;
   289→        b[511] = 0xAA; // signature
   290→    }
   291→
   292→    // ── Block 1: Boot sector (FAT16 BPB) ─────────────────────────────────────
   293→    {
   294→        let b = &mut blocks[1].contents;
   295→        b[0] = 0xEB;
   296→        b[1] = 0x3C;
   297→        b[2] = 0x90; // jump boot
   298→        b[3..11].copy_from_slice(b"PAPERDOS"); // OEM name
   299→        b[11] = 0x00;
   300→        b[12] = 0x02; // bytes per sector = 512
   301→        b[13] = 0x01; // sectors per cluster
   302→        b[14] = 0x01;
   303→        b[15] = 0x00; // reserved sectors = 1
   304→        b[16] = 0x01; // num FATs
   305→        b[17] = 0x10;
   306→        b[18] = 0x00; // root entries = 16
   307→        b[19] = 0x68;
   308→        b[20] = 0x10; // total sectors = 4200 (0x1068 LE)
   309→        b[21] = 0xF8; // media = fixed
   310→        b[22] = 0x11;
   311→        b[23] = 0x00; // FAT size = 17
   312→        b[24] = 0x3F;
   313→        b[25] = 0x00; // sectors/track
   314→        b[26] = 0xFF;
   315→        b[27] = 0x00; // num heads
   316→        b[28] = 0x01;
   317→        b[29] = 0x00;
   318→        b[30] = 0x00;
   319→        b[31] = 0x00; // hidden sectors = 1
   320→                      // total_sectors32 at 32-35: zero (use 16-bit field above)
   321→        b[36] = 0x80; // drive number
   322→        b[38] = 0x29; // extended boot signature
   323→        b[39] = 0x01;
   324→        b[40] = 0x02;
   325→        b[41] = 0x03;
   326→        b[42] = 0x04; // volume serial
   327→        b[43..54].copy_from_slice(b"PAPERDOS   "); // volume label (11 bytes)
   328→        b[54..62].copy_from_slice(b"FAT16   "); // FS type
   329→        b[510] = 0x55;
   330→        b[511] = 0xAA; // signature
   331→    }
   332→
   333→    // ── Block 2: FAT sector 0 ─────────────────────────────────────────────────
   334→    {
   335→        let b = &mut blocks[2].contents;
   336→        b[0] = 0xF8;
   337→        b[1] = 0xFF; // entry 0: media marker 0xFFF8
   338→        b[2] = 0xFF;
   339→        b[3] = 0xFF; // entry 1: end-of-chain
   340→        b[4] = 0xFF;
   341→        b[5] = 0xFF; // entry 2: README.TXT (single cluster)
   342→        b[6] = 0xFF;
   343→        b[7] = 0xFF; // entry 3: TESTDIR (single cluster)
   344→    }
   345→
   346→    // ── Block 19: Root directory ──────────────────────────────────────────────
   347→    {
   348→        let b = &mut blocks[19].contents;
   349→        // Entry 0: README.TXT — "README  TXT", ARCHIVE, cluster=2, size=6
   350→        b[0..11].copy_from_slice(b"README  TXT");
   351→        b[11] = 0x20; // attribute: ARCHIVE
   352→        b[26] = 0x02;
   353→        b[27] = 0x00; // first cluster = 2
   354→        b[28] = 0x06;
   355→        b[29] = 0x00;
   356→        b[30] = 0x00;
   357→        b[31] = 0x00; // size = 6
   358→
   359→        // Entry 1: TESTDIR — "TESTDIR    ", DIRECTORY, cluster=3
   360→        b[32..43].copy_from_slice(b"TESTDIR    ");
   361→        b[43] = 0x10; // attribute: DIRECTORY
   362→        b[58] = 0x03;
   363→        b[59] = 0x00; // first cluster = 3
   364→                      // size = 0 (already zero)
   365→    }
   366→
   367→    // ── Block 20: Cluster 2 = README.TXT content ─────────────────────────────
   368→    blocks[20].contents[0..6].copy_from_slice(b"Hello!");
   369→
   370→    // Block 21: Cluster 3 = TESTDIR — all zeros (already initialized)
   371→
   372→    blocks
   373→}
