   492→/// Build a FAT16 disk image containing two valid `.PDB` files in the root directory.
   493→///
   494→/// Unlike `make_apps_fat16_image`, each file holds a fully-valid PDB produced by
   495→/// `make_min_pdb`, so the loader can parse and relocate them.
   496→///
   497→/// Layout (device LBAs, same BPB as `make_test_fat16_image`):
   498→///  0  : MBR  — FAT16, LBA start=1, size=4200
   499→///  1  : Boot sector
   500→///  2-18: FAT — clusters 2 and 3 marked end-of-chain
   501→///  19 : Root directory — HELLO.PDB (cluster 2) + WORLD.PDB (cluster 3)
   502→///  20 : Cluster 2 — `make_min_pdb(&[0u8; 4])` image
   503→///  21 : Cluster 3 — `make_min_pdb(&[1u8, 2, 3, 4])` image
   504→pub fn make_valid_apps_fat16_image() -> Vec<Block> {
   505→    let hello = make_min_pdb(&[0u8; 4]);
   506→    let world = make_min_pdb(&[1u8, 2, 3, 4]);
   507→    assert!(hello.len() <= 512);
   508→    assert!(world.len() <= 512);
   509→
   510→    const TOTAL: usize = 4201;
